Why don't you just make exeption on rediction from http to https for LE/Acme-tiny specifically? I've done such for both Apache and Nginx instances, Examples:

.htaccess snippet for Apache:
`
RewriteCond %{ENV:HTTPS} !=on
RewriteCond %{REQUEST_URI} !^/?\.well-known/acme-challenge/
RewriteRule ^(.*)$ https://%{HTTP_HOST}%{REQUEST_URI} [L,R=301,NC]
`

site config snippet for Nginx:
`
server {
    listen 80;
    location /.well-known/acme-challenge/ {
        alias /directory/for/acme-challenge/location/;
        try_files $uri =404;
    }

    location / {
        return 301 https://$server_name$request_uri;
    }
}
`

Ofcourse snippets aren't full configurationfiles but the portion related to issue at hand. Hope this helps :)

Hi,

First at all, I am sorry for my delay in the answer but I was working in others topics. Finally I used this option in knockout:

 /*Extends Pagination*/
	(function() {
	    'use strict';
	    ko.extenders.paging = function(target, pageSize) {
	        var _pageSize = ko.observable(pageSize || 10),
	            // default pageSize to 10
	            _currentPage = ko.observable(1); // default current page to 1
	        target.pageSize = ko.computed({
	            read: _pageSize,
	            write: function(newValue) {
	                if (newValue > 0) {
	                    _pageSize(newValue);
	                }
	                else {
	                    _pageSize(10);
	                }
	            }
	        });

	        target.currentPage = ko.computed({
	            read: _currentPage,
	            write: function(newValue) {
	                if (newValue > target.pageCount()) {
	                    _currentPage(target.pageCount());
	                }
	                else if (newValue <= 0) {
	                    _currentPage(1);
	                }
	                else {
	                    _currentPage(newValue);
	                }
	            }
	        });

	        target.pageCount = ko.computed(function() {
	            return Math.ceil(target().length / target.pageSize()) || 1;
	        });

	        target.currentPageData = ko.computed(function() {
	            var pageSize = _pageSize(),
	                pageIndex = _currentPage(),
	                startIndex = pageSize * (pageIndex - 1),
	                endIndex = pageSize * pageIndex;

	            return target().slice(startIndex, endIndex);
	        });

	        target.moveFirst = function() {
	            target.currentPage(1);
	        };
	        target.movePrevious = function() {
	            target.currentPage(target.currentPage() - 1);
	        };
	        target.moveNext = function() {
	            target.currentPage(target.currentPage() + 1);
	        };
	        target.moveLast = function() {
	            target.currentPage(target.pageCount());
	        };

	        return target;
	    };
	}());

